#include <stdio.h>
#include <limits.h>

typedef long long ll;
typedef unsigned long long ull;

#define REP(i, n) for((i) = 0; (i) < (n); (i)++)
#define REP1(i, n) for((i) = 1; (i) <= (n); (i)++)

#define SIZE 1000002

static int s[SIZE], p[SIZE], np, min;

static void sieve(void)
{
  int i, j;

  for (i = 2; i < SIZE; i++) {
    if (s[i] == 0) {
      p[np++] = i;

      for (j = 2; i * j < SIZE; j++) {
        s[i * j] = 1;
      }
    }
  }
}

#define MAX(x, y) ((x) > (y) ? (x) : (y))

static void solve(int x, int l)
{
  int i, d, lf = -1, ox = x;

  if (x < min) {
    min = x;
  }

  if (l == 0) {
    return;
  }

  for (i = 0; p[i] * p[i] <= x; i++) {
    if (ox % p[i] == 0) {
      lf = MAX(lf, p[i]);
      while (ox % p[i] == 0)
        ox /= p[i];
    }
  }
  if (ox > 1 && ox != x)
    lf = MAX(lf, ox);

  if (lf == -1) {
    return;
  }

  if (l == 1) {
    x = x - lf + 1;
    if(x < min)
      min = x;
    return;
  }

  for (d = x - lf + 1; d < lf * (x / lf); d++) {
    solve(d, l - 1);
  }
}

int main(void)
{
  int x2;

  s[0] = s[1] = 1;
  sieve();
  min = INT_MAX;

  scanf("%d", &x2);
  solve(x2, 2);
  printf("%d", min);

  return 0;
}

