    let mut input = String::new();
    use std::io::{self, prelude::*};
    io::stdin().read_to_string(&mut input).unwrap();

    let x_2: usize = input.trim().parse().unwrap();

    // Le troisième exemple est assez surprenant. 8192 = 2^13,
    // Il faut que le nombre premier choisi par Bob divise le résultat, ce qui
    // explique déjà le troisième exemple. X_2 est composite par hypothèse. On
    // envisage de prendre son plus petit diviseur premier comme choix de Bob.
    // X_2 = p * k. On a p * (k - 1) < X_1 <= X_2

    let n = 1_000_001;

    let mut fl = vec![0; n];

    for i in 2..= 1_000 {
        if fl[i] != 0 {
            continue;
        }
        let mut x = 2 * i;
        while x < n {
            if fl[x] == 0 {
                fl[x] = i;
            }
            x += i;
        }
    }

    let gpd = |mut i| {
        while i != fl[i] && fl[i] != 0 {
            i /= fl[i];
        }
        i
    };

    let mut ans = None;

    let gpd_2 = gpd(x_2);
    let k_2 = x_2 / gpd_2;

    for x_1 in gpd_2 * (k_2 - 1) + 1..=x_2 {
        let gpd_1 = gpd(x_1);
        let cand = if fl[x_1] == 0 { x_1 } else {
            (x_1 / gpd_1 - 1) * gpd_1 + 1
        };
        match ans {
            Some(a) if a <= cand => (),
            _ => ans = Some(cand),
        }
    }

    println!("{}", ans.unwrap());
}
